import { useLocation, useNavigate } from "react-router-dom";

function QuizResult() {
  const location = useLocation();
  const navigate = useNavigate();

  const result = location.state;

  if (!result) {
    return (
      <div style={{ padding: "30px", color: "black" }}>
        <h2>No result found.</h2>
        <button onClick={() => navigate("/quiz-bank")}>Go Back</button>
      </div>
    );
  }

  return (
    <div style={{ padding: "30px", color: "black" }}>
      <h1>Quiz Result</h1>
      <h2>{result.title}</h2>
      <p>
        You scored <strong>{result.score}</strong> out of <strong>{result.total}</strong>
      </p>

      <button
        onClick={() => navigate("/quiz-bank")}
        style={{ marginTop: "20px", padding: "10px 16px", cursor: "pointer" }}
      >
        Back to Quiz Bank
      </button>
    </div>
  );
}

export default QuizResult;
